using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch a user by ID from the REST API.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var json = await httpClient.GetStringAsync(
            $"/users/{userId}", cancellationToken);
        return json;
    }

    [McpServerTool, Description("Search users by name. Returns matching results as JSON.")]
    public async Task<string> SearchUsers(
        [Description("Name or partial name to search for")] string query,
        [Description("Max results to return (1-50)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users: {Query}, limit={Limit}", query, limit);
        var response = await httpClient.GetAsync(
            $"/users?q={Uri.EscapeDataString(query)}&limit={limit}",
            cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(ReadOnly = false, Destructive = false),
     Description("Create a new user with the given name and email.")]
    public async Task<string> CreateUser(
        [Description("Full name of the user")] string name,
        [Description("Email address")] string email,
        CancellationToken cancellationToken = default)
    {
        var payload = JsonSerializer.Serialize(new { name, email });
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/users", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

var builder = Host.CreateApplicationBuilder(args);

// CRITICAL: route all logging to stderr so stdout stays clean for JSON-RPC
builder.Logging.AddConsole(options =>
    options.LogToStandardErrorThreshold = LogLevel.Trace);

// Register HttpClient with a base address for the API
builder.Services.AddHttpClient<ApiTools>(client =>
{
    client.BaseAddress = new Uri("https://api.example.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
});

builder.Services.AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();   // discovers all [McpServerToolType] classes

await builder.Build().RunAsync();

